import { task } from "@trigger.dev/sdk";
export const helloWorld = task({
id: "hello-world",
run: async (payload: { name: string }) => {
console.log(`Hello ${payload.name}!`);
return {
message: `Hello ${payload.name}!`,
timestamp: new Date().toISOString(),
};
},
});
```
…
```
import { useRealtimeRun } from "@trigger.dev/react-hooks";
export function TaskStatus({
runId,
publicAccessToken,
}: {
runId: string;
publicAccessToken: string;
}) {
const { run, error } = useRealtimeRun(runId, {
accessToken: publicAccessToken,
});
if (error) return <div>Error: {error.message}</div>;
if (!run) return <div>Loading...</div>;
return (
<div>
<p>Status: {run.status}</p>
<p>Progress: {run.completedAt ? "Complete" : "Running..."}</p>
</div>
);
}
```

# https://trigger.dev/docs/llms-full.txt
created: undefined, last updated: 2026-04-25, [Read more](https://trigger.dev/docs/llms-full.txt)

How to authenticate with Trigger.dev so you can trigger tasks.
### Authentication and your secret keys
When you [trigger a task](/triggering) from your backend code, you need to set the `TRIGGER_SECRET_KEY` environment variable.
...
### From inside other tasks
```ts
export const parentTask = task({
id: "parent-task",
run: async (payload) => {
// Fire and forget
await childTask.trigger({ data: "value" });
// Wait for result — returns a Result object, NOT the output directly
const result = await childTask.triggerAndWait({ data: "value" });
if (result.ok) {
console.log(result.output); // The actual return value
} else {
console.error(result.error);
}
…
4. **Calling `task.trigger()` directly** — use `tasks.trigger<typeof myTask>("task-id", payload)` from your backend
5.
**Using `triggerAndWait` result as output** — it returns a `Result` object; check `result.ok` then access `result.output`, or use `.unwrap()`

